import json
import re
from collections import Counter

import modal

app = modal.App("document-analytics-pipeline")
image = modal.Image.debian_slim()

report_volume = modal.Volume.from_name(
    "document-analytics-pipeline-vol", create_if_missing=True
)
output_dict = modal.Dict.from_name(
    "document-analytics-pipeline-output", create_if_missing=True
)


@app.cls(image=image)
class DocumentAnalyzer:
    @modal.enter()
    def setup_pipeline(self) -> None:
        self.word_pattern = re.compile(r"[a-zA-Z0-9']+")

    @modal.method()
    def analyze(self, document: str) -> dict:
        tokens = [token.lower() for token in self.word_pattern.findall(document)]
        counts = Counter(tokens)
        top_words = [
            {"word": word, "count": count}
            for word, count in counts.most_common(3)
        ]
        return {
            "word_count": len(tokens),
            "unique_word_count": len(counts),
            "top_words": top_words,
        }


@app.function(image=image, volumes={"/reports": report_volume})
def write_report(report: dict) -> str:
    report_path = "/reports/analytics_report.json"
    with open(report_path, "w", encoding="utf-8") as report_file:
        json.dump(report, report_file, indent=2)
    report_volume.commit()
    return report_path


@app.local_entrypoint()
def main() -> None:
    documents = [
        "Modal makes it easy to run Python in the cloud with serverless GPUs.",
        "Document analytics can extract insights from large text corpora.",
        "Parallel processing helps analyze multiple documents efficiently.",
        "Regex tokenization keeps this pipeline lightweight and reliable.",
        "Collections counters make frequency analysis straightforward.",
        "Modal volumes persist analytics reports across runs.",
    ]

    analyzer = DocumentAnalyzer()
    results = list(analyzer.analyze.map(documents))

    total_documents = len(results)
    total_words = sum(result["word_count"] for result in results)
    avg_words_per_doc = total_words / total_documents if total_documents else 0.0

    report = {
        "documents": [
            {"document": index + 1, **result} for index, result in enumerate(results)
        ],
        "aggregates": {
            "total_documents": total_documents,
            "total_words": total_words,
            "avg_words_per_doc": avg_words_per_doc,
        },
    }

    report_path = write_report.remote(report)

    output_dict["total_documents"] = total_documents
    output_dict["total_words"] = total_words
    output_dict["avg_words_per_doc"] = avg_words_per_doc
    output_dict["report_path"] = report_path

    print(f"Report written to {report_path}")
